import jwt
import datetime

SECRET_KEY = 'your-strong-secret-key'  # Use a strong, random key

def generate_jwt(user_id, role):
    expiration = datetime.datetime.utcnow() + datetime.timedelta(hours=1)
    token = jwt.encode({
        'user_id': user_id,
        'role': role,
        'exp': expiration
    }, SECRET_KEY, algorithm='HS256')  # Explicit algorithm
